#!/usr/bin/env perl
#
# Perl port of examples/c/hello-world.c using the autogenerated
# bindings from `doc/src/codegen/v2/lang_perl/`. Same shape as
# examples/ruby/hello-world.rb and examples/lua/hello-world.lua —
# `Azul::RefAny->wrap(scalar)` stashes a Perl ref, callbacks are plain
# Perl subs, and the framework keeps everything alive via RefAny refcount.
#
# Callbacks go through libazul's host-invoker plumbing
# (`AzCallback_createFromHostHandle`, `AzApp_setCallbackInvoker`) so the
# Perl sub is held alive by the framework's RefAny refcount; there's no
# per-callback `FFI::Platypus::Closure` to manage by hand.
#
# Run with:
#     cpanm --installdeps .
#     perl -Ilib hello-world.pl
#
# `lib/` is expected to contain the generated `Azul.pm` (azul-doc
# emits this at `target/codegen/Azul.pm`); symlink it next to this
# file or set PERL5LIB if your output lives elsewhere.
#
# ── Codegen status ──────────────────────────────────────────────────
# As of this commit the host-invoker prelude is wired for Lua and Ruby.
# The Perl adapter (`lang_perl/`) needs an analogous `managed.rs`
# emitting:
#   * `$ffi->attach('AzApp_setHostHandleReleaser', ['(uint64)->void'], 'void')`
#   * `$ffi->attach('AzCallback_createFromHostHandle', ['uint64'], 'AzCallback')`
#     (and the matching LayoutCallback / VirtualViewCallback variants)
#   * a `%_perl_handles` package hash + `Azul::register_callback`.
# Once that lands this example runs unchanged.

use strict;
use warnings;
use FindBin qw($Bin);
use lib "$Bin/../../target/codegen";

use Azul;

use constant {
    Update_DoNothing  => Azul::Update::DoNothing,
    Update_RefreshDom => Azul::Update::RefreshDom,
};

# ── Data model ──────────────────────────────────────────────────────
#
# `Azul::RefAny->wrap($scalar)` stashes the value in a package-level
# id-keyed hash and returns an AzRefAny whose payload is just the id.
# The destructor that fires on the last clone calls back through
# `AzApp_setHostHandleReleaser` to drop the hash entry.

my $model = { counter => 5 };
my $data  = Azul::RefAny->wrap($model);

# ── Callback: button click ──────────────────────────────────────────

my $on_click = sub {
    my ($data_ptr, $info_ptr) = @_;
    my $m = Azul::RefAny->unwrap($data_ptr);
    return Update_DoNothing unless defined $m;
    $m->{counter}++;
    return Update_RefreshDom;
};

# ── Callback: layout (rebuilds DOM each frame) ──────────────────────

my $layout = sub {
    my ($data_ptr, $info_ptr) = @_;
    my $m = Azul::RefAny->unwrap($data_ptr);
    return Azul::Dom->create_body unless defined $m;

    # Counter label (wrapped in a div so the font-size sticks).
    my $label_text    = Azul::String->copy_from_string($m->{counter});
    my $label         = Azul::Dom->create_text($label_text);
    my $label_wrapper = Azul::Dom->create_div;
    $label_wrapper->add_css_property(
        Azul::CssPropertyWithConditions->simple(
            Azul::CssProperty->font_size(Azul::StyleFontSize->px(32.0))
        )
    );
    $label_wrapper->add_child($label);

    # Increment button. The wrapper auto-routes `$on_click` through
    # `Azul::register_callback('Callback', $sub)` once the codegen
    # adapter lands; until then the user passes the sub directly and
    # the binding stashes it.
    my $button = Azul::Button->create(
        Azul::String->copy_from_string('Increase counter')
    );
    $button->set_button_type(Azul::ButtonType::Primary);
    $button->set_on_click(Azul::RefAny->clone($data_ptr), $on_click);
    my $button_dom = $button->dom;

    # Body
    my $body = Azul::Dom->create_body;
    $body->add_child($label_wrapper);
    $body->add_child($button_dom);
    return $body;
};

# ── Main ────────────────────────────────────────────────────────────

my $window = Azul::WindowCreateOptions->create($layout);
$window->window_state->title(
    Azul::String->copy_from_string('Hello World')
);
$window->window_state->size->dimensions->width(400.0);
$window->window_state->size->dimensions->height(300.0);

# NoTitleAutoInject: OS draws close/min/max buttons, framework
# auto-injects a Titlebar with drag support.
$window->window_state->flags->decorations(
    Azul::WindowDecorations::NoTitleAutoInject
);
$window->window_state->flags->background_material(
    Azul::WindowBackgroundMaterial::Sidebar
);

my $app = Azul::App->create($data, Azul::AppConfig->create);
$app->run($window);

# $app falls out of scope here; Perl's DESTROY calls AzApp_delete.
exit 0;
